import Foundation
import SwiftData

// Bump this number whenever new exercises are added — the app will reseed on next launch.
private let kCatalogVersion = 2

enum ExerciseCatalog {

    static func seedIfNeeded(context: ModelContext) {
        let saved = UserDefaults.standard.integer(forKey: "exerciseCatalogVersion")
        guard saved < kCatalogVersion else { return }

        // Remove all non-custom global exercises so we can replace with the full catalog.
        let descriptor = FetchDescriptor<ExerciseDefinitionRecord>(
            predicate: #Predicate { !$0.isCustom && $0.ownerID == "" }
        )
        if let stale = try? context.fetch(descriptor) {
            stale.forEach { context.delete($0) }
        }

        for ex in catalog {
            context.insert(ExerciseDefinitionRecord(
                name: ex.0,
                primaryMuscle: ex.1,
                secondaryMusclesJSON: encodeSecondary(ex.2),
                equipment: ex.3,
                movementPattern: ex.4
            ))
        }
        try? context.save()
        UserDefaults.standard.set(kCatalogVersion, forKey: "exerciseCatalogVersion")
    }

    private static func encodeSecondary(_ muscles: [String]) -> String {
        (try? String(data: JSONEncoder().encode(muscles), encoding: .utf8)) ?? "[]"
    }

